import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useStore, Role } from '../store/useStore';
import { Shield, GraduationCap, User, Building2, ChevronDown, Eye, EyeOff } from 'lucide-react';

interface ParticleProps {
  style: React.CSSProperties;
}

function Particle({ style }: ParticleProps) {
  return <div className="particle" style={style} />;
}

interface RingWaveProps {
  style: React.CSSProperties;
}

function RingWave({ style }: RingWaveProps) {
  return <div className="ring-wave" style={style} />;
}

interface FlowLineProps {
  style: React.CSSProperties;
}

function FlowLine({ style }: FlowLineProps) {
  return <div className="flow-line" style={style} />;
}

interface GridLineProps {
  style: React.CSSProperties;
}

function GridLine({ style }: GridLineProps) {
  return <div className="grid-line" style={style} />;
}

interface GeoSliceProps {
  style: React.CSSProperties;
}

function GeoSlice({ style }: GeoSliceProps) {
  return <div className="geo-slice" style={style} />;
}

interface DataNodeProps {
  style: React.CSSProperties;
}

function DataNode({ style }: DataNodeProps) {
  return <div className="data-node" style={style} />;
}

interface NebulaParticleProps {
  style: React.CSSProperties;
}

function NebulaParticle({ style }: NebulaParticleProps) {
  return <div className="nebula-particle" style={style} />;
}

const roleOptions: { role: Role; name: string; icon: React.ReactNode }[] = [
  { role: 'admin', name: '超级管理员', icon: <Shield className="w-5 h-5" /> },
  { role: 'teacher', name: '教师', icon: <GraduationCap className="w-5 h-5" /> },
  { role: 'student', name: '学生', icon: <User className="w-5 h-5" /> },
];

const defaultCredentials: Record<Role, { username: string; password: string }> = {
  admin: { username: 'admin', password: '123456' },
  teacher: { username: 'teacher', password: '123456' },
  student: { username: 'student', password: '123456' },
};

export default function Login() {
  const [selectedRole, setSelectedRole] = useState<Role | null>(null);
  const [showRoleDropdown, setShowRoleDropdown] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [error, setError] = useState('');
  
  const navigate = useNavigate();
  const login = useStore((state) => state.login);

  const handleRoleSelect = (role: Role) => {
    setSelectedRole(role);
    setShowRoleDropdown(false);
    const creds = defaultCredentials[role];
    setUsername(creds.username);
    setPassword(creds.password);
    setError('');
  };

  const handleLogin = async () => {
    if (!selectedRole) {
      setError('请先选择登录身份');
      return;
    }
    if (!username || !password) {
      setError('请输入账号和密码');
      return;
    }
    
    setIsLoggingIn(true);
    setError('');
    
    setTimeout(() => {
      if (login(username, password, selectedRole)) {
        navigate('/');
      } else {
        setError('账号或密码错误');
        setIsLoggingIn(false);
      }
    }, 500);
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      if (!selectedRole) {
        setShowRoleDropdown(true);
      } else {
        handleLogin();
      }
    }
  };

  const particles = Array.from({ length: 25 }, (_, i) => ({
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100}%`,
    size: `${2 + Math.random() * 4}px`,
    animationDelay: `${Math.random() * 10}s`,
    animationDuration: `${10 + Math.random() * 10}s`,
  }));

  const ringWaves = Array.from({ length: 4 }, (_, i) => ({
    size: `${200 + i * 150}px`,
    animationDelay: `${i * 2}s`,
    animationDuration: `${8 + i * 2}s`,
  }));

  const flowLines = Array.from({ length: 8 }, (_, i) => ({
    top: `${10 + i * 12}%`,
    animationDelay: `${Math.random() * 8}s`,
    animationDuration: `${15 + Math.random() * 10}s`,
  }));

  const gridLinesH = Array.from({ length: 12 }, (_, i) => ({
    top: `${i * 8.3}%`,
    animationDelay: `${i * 0.3}s`,
  }));

  const gridLinesV = Array.from({ length: 12 }, (_, i) => ({
    left: `${i * 8.3}%`,
    animationDelay: `${i * 0.3}s`,
  }));

  const geoSlices = Array.from({ length: 6 }, (_, i) => ({
    top: `${20 + (i % 3) * 30}%`,
    left: `${10 + Math.floor(i / 3) * 40}%`,
    rotate: `${i * 30}deg`,
    scale: `${0.8 + (i % 3) * 0.2}`,
    animationDelay: `${i * 1.5}s`,
    animationDuration: `${20 + i * 5}s`,
  }));

  const dataNodes = Array.from({ length: 15 }, (_, i) => ({
    left: `${15 + Math.random() * 70}%`,
    top: `${15 + Math.random() * 70}%`,
    size: `${4 + Math.random() * 8}px`,
    animationDelay: `${Math.random() * 15}s`,
    animationDuration: `${8 + Math.random() * 12}s`,
  }));

  const nebulaParticles = Array.from({ length: 20 }, (_, i) => ({
    left: `${Math.random() * 100}%`,
    top: `${Math.random() * 100}%`,
    size: `${20 + Math.random() * 60}px`,
    animationDelay: `${Math.random() * 20}s`,
    animationDuration: `${25 + Math.random() * 20}s`,
    opacity: `${0.02 + Math.random() * 0.03}`,
  }));

  const getSelectedRoleOption = () => {
    return roleOptions.find((opt) => opt.role === selectedRole);
  };

  return (
    <div className="min-h-screen flex flex-col relative overflow-hidden">
      <div className="absolute inset-0 bg-gradient-to-br from-[#1a0f2e] via-[#2d1b4e] to-[#3A2460]" />
      
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2">
          {ringWaves.map((ring, index) => (
            <RingWave
              key={`ring-${index}`}
              style={{
                width: ring.size,
                height: ring.size,
                animationDelay: ring.animationDelay,
                animationDuration: ring.animationDuration,
              }}
            />
          ))}
        </div>

        {flowLines.map((line, index) => (
          <FlowLine
            key={`flow-${index}`}
            style={{
              top: line.top,
              animationDelay: line.animationDelay,
              animationDuration: line.animationDuration,
            }}
          />
        ))}

        {particles.map((particle, index) => (
          <Particle
            key={`particle-${index}`}
            style={{
              left: particle.left,
              top: particle.top,
              width: particle.size,
              height: particle.size,
              animationDelay: particle.animationDelay,
              animationDuration: particle.animationDuration,
            }}
          />
        ))}

        {gridLinesH.map((line, index) => (
          <GridLine
            key={`grid-h-${index}`}
            style={{
              top: line.top,
              animationDelay: line.animationDelay,
              transform: 'scaleX(1)',
            }}
          />
        ))}

        {gridLinesV.map((line, index) => (
          <GridLine
            key={`grid-v-${index}`}
            style={{
              left: line.left,
              animationDelay: line.animationDelay,
              transform: 'scaleY(1)',
            }}
          />
        ))}

        {geoSlices.map((slice, index) => (
          <GeoSlice
            key={`geo-${index}`}
            style={{
              top: slice.top,
              left: slice.left,
              transform: `rotate(${slice.rotate}) scale(${slice.scale})`,
              animationDelay: slice.animationDelay,
              animationDuration: slice.animationDuration,
            }}
          />
        ))}

        {dataNodes.map((node, index) => (
          <DataNode
            key={`node-${index}`}
            style={{
              left: node.left,
              top: node.top,
              width: node.size,
              height: node.size,
              animationDelay: node.animationDelay,
              animationDuration: node.animationDuration,
            }}
          />
        ))}

        {nebulaParticles.map((particle, index) => (
          <NebulaParticle
            key={`nebula-${index}`}
            style={{
              left: particle.left,
              top: particle.top,
              width: particle.size,
              height: particle.size,
              animationDelay: particle.animationDelay,
              animationDuration: particle.animationDuration,
              opacity: particle.opacity,
            }}
          />
        ))}

        <div className="absolute top-1/4 left-1/3 w-96 h-96 bg-secondary-400/8 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/3 w-80 h-80 bg-purple-500/6 rounded-full blur-3xl" />
        <div className="absolute top-1/2 right-1/4 w-64 h-64 bg-secondary-400/5 rounded-full blur-2xl" />
        <div className="absolute bottom-1/3 left-1/4 w-48 h-48 bg-purple-400/4 rounded-full blur-2xl" />
      </div>

      <header className="relative z-10 py-16 text-center">
        <div className="inline-flex items-center gap-4 mb-6">
          <div className="w-14 h-14 bg-gradient-to-br from-secondary-400 to-primary-900 rounded-card flex items-center justify-center shadow-lg shadow-purple-500/20">
            <Building2 className="w-8 h-8 text-white" />
          </div>
          <h1 className="text-4xl font-bold text-white tracking-wide">一体化平台</h1>
        </div>
        <p className="text-gray-400 text-lg">搭建融合教学、考试、实训的一站式智慧校园数字平台</p>
      </header>

      <main className="relative z-10 flex-1 flex items-center justify-center px-4 py-8">
        <div className="w-full max-w-md">
          <div className="login-card p-8">
            <div className="text-center mb-8">
              <h2 className="text-xl font-bold text-white mb-2">用户登录</h2>
              <p className="text-gray-400 text-sm">请选择身份并输入账号密码</p>
            </div>

            <div className="space-y-6">
              <div className="relative">
                <label className="block text-gray-300 text-sm font-medium mb-2">登录身份</label>
                <button
                  onClick={() => setShowRoleDropdown(!showRoleDropdown)}
                  onKeyPress={handleKeyPress}
                  className="w-full flex items-center justify-between px-4 py-3 bg-white/5 border border-white/10 rounded-card text-left hover:border-secondary-400/40 hover:bg-white/10 transition-all duration-300"
                >
                  {selectedRole ? (
                    <div className="flex items-center gap-3">
                      {getSelectedRoleOption()?.icon}
                      <span className="text-white">{getSelectedRoleOption()?.name}</span>
                    </div>
                  ) : (
                    <span className="text-gray-500">请选择登录身份</span>
                  )}
                  <ChevronDown className={`w-5 h-5 text-gray-400 transition-transform duration-300 ${showRoleDropdown ? 'rotate-180' : ''}`} />
                </button>
                
                {showRoleDropdown && (
                  <div className="absolute top-full left-0 right-0 mt-2 bg-primary-900/90 backdrop-blur-xl border border-white/10 rounded-card shadow-soft-hover z-20 animate-fade-in">
                    {roleOptions.map((option) => (
                      <button
                        key={option.role}
                        onClick={() => handleRoleSelect(option.role)}
                        className={`w-full flex items-center gap-3 px-4 py-3 hover:bg-white/10 transition-colors ${
                          selectedRole === option.role ? 'bg-secondary-400/20' : ''
                        }`}
                      >
                        {option.icon}
                        <span className={selectedRole === option.role ? 'text-secondary-400' : 'text-gray-300'}>
                          {option.name}
                        </span>
                      </button>
                    ))}
                  </div>
                )}
              </div>

              {selectedRole && (
                <>
                  <div>
                    <label className="block text-gray-300 text-sm font-medium mb-2">账号</label>
                    <input
                      type="text"
                      value={username}
                      onChange={(e) => { setUsername(e.target.value); setError(''); }}
                      onKeyPress={handleKeyPress}
                      placeholder="请输入账号"
                      className="input-glass w-full"
                    />
                  </div>

                  <div className="relative">
                    <label className="block text-gray-300 text-sm font-medium mb-2">密码</label>
                    <div className="relative">
                      <input
                        type={showPassword ? 'text' : 'password'}
                        value={password}
                        onChange={(e) => { setPassword(e.target.value); setError(''); }}
                        onKeyPress={handleKeyPress}
                        placeholder="请输入密码"
                        className="input-glass w-full pr-12"
                      />
                      <button
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-3 top-1/2 -translate-y-1/2 flex items-center justify-center text-gray-400 hover:text-white transition-colors"
                      >
                        {showPassword ? <EyeOff className="w-5 h-5" /> : <Eye className="w-5 h-5" />}
                      </button>
                    </div>
                  </div>

                  {error && (
                    <p className="text-red-400 text-sm text-center animate-fade-in">{error}</p>
                  )}

                  <button
                    onClick={handleLogin}
                    disabled={isLoggingIn}
                    className="btn-primary w-full flex items-center justify-center gap-2"
                  >
                    {isLoggingIn ? (
                      <>
                        <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                        <span>登录中...</span>
                      </>
                    ) : (
                      <span>登 录</span>
                    )}
                  </button>

                  <div className="flex items-center justify-center gap-4 pt-4 border-t border-white/10">
                    <span className="text-gray-500 text-xs">默认账号：{defaultCredentials[selectedRole].username}</span>
                    <span className="text-gray-500 text-xs">默认密码：{defaultCredentials[selectedRole].password}</span>
                  </div>
                </>
              )}
            </div>
          </div>
        </div>
      </main>

      <footer className="relative z-10 py-4 text-center">
        <p className="text-gray-500 text-sm">© 2026 一体化平台</p>
      </footer>
    </div>
  );
}