function AiPractice() {
  const [messages, setMessages] = useState<ChatMessage[]>(mockChatMessages);
  const [inputValue, setInputValue] = useState('');

  const handleSend = () => {
    if (!inputValue.trim()) return;
    const newMessage: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      content: inputValue,
      time: new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' }),
    };
    setMessages((prev) => [...prev, newMessage]);
    setInputValue('');

    setTimeout(() => {
      const reply: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'assistant',
        content: '感谢您的提问！我正在为您整理相关信息，请稍候...\n\n这是AI助教的智能回复示例，实际系统中将接入真实的AI能力。',
        time: new Date().toLocaleTimeString('zh-CN', { hour: '2-digit', minute: '2-digit' }),
      };
      setMessages((prev) => [...prev, reply]);
    }, 1000);
  };

  return (
    <div className="space-y-6">
      <div className="glass-card p-6">
        <div className="flex items-center gap-3 mb-6">
          <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-blue-500/30 to-purple-500/30 flex items-center justify-center">
            <Brain className="w-6 h-6 text-secondary-400" />
          </div>
          <div>
            <h2 className="text-lg font-semibold text-white">智问AI实践助手</h2>
            <p className="text-gray-400 text-sm">智能教学辅助，随时随地解答疑问</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-6">
          <div className="p-4 bg-gradient-to-br from-blue-500/10 to-primary-900/20 rounded-xl border border-blue-500/20">
            <div className="flex items-center gap-3 mb-2">
              <Sparkles className="w-5 h-5 text-blue-400" />
              <span className="text-white font-medium">智能问答</span>
            </div>
            <p className="text-gray-400 text-sm">基于AI技术的智能问答系统，支持课程知识点查询、学习方法指导</p>
          </div>
          <div className="p-4 bg-gradient-to-br from-green-500/10 to-primary-900/20 rounded-xl border border-green-500/20">
            <div className="flex items-center gap-3 mb-2">
              <Lightbulb className="w-5 h-5 text-green-400" />
              <span className="text-white font-medium">学习推荐</span>
            </div>
            <p className="text-gray-400 text-sm">根据学习进度智能推荐相关资源，精准匹配学习需求</p>
          </div>
          <div className="p-4 bg-gradient-to-br from-purple-500/10 to-primary-900/20 rounded-xl border border-purple-500/20">
            <div className="flex items-center gap-3 mb-2">
              <FileText className="w-5 h-5 text-purple-400" />
              <span className="text-white font-medium">资料整理</span>
            </div>
            <p className="text-gray-400 text-sm">自动整理课程资料，生成知识点图谱和学习笔记</p>
          </div>
        </div>

        <div className="h-96 bg-black/30 rounded-xl p-4 flex flex-col">
          <div className="flex-1 overflow-y-auto space-y-4 mb-4">
            {messages.map((msg) => (
              <div key={msg.id} className={`flex gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}>
                <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${
                  msg.role === 'user' ? 'bg-secondary-400' : 'bg-primary-500/50'
                }`}>
                  {msg.role === 'user' ? (
                    <Users className="w-4 h-4 text-white" />
                  ) : (
                    <Brain className="w-4 h-4 text-secondary-400" />
                  )}
                </div>
                <div className={`max-w-[70%] ${msg.role === 'user' ? 'text-right' : ''}`}>
                  <div className={`inline-block px-4 py-2 rounded-xl ${
                    msg.role === 'user' 
                      ? 'bg-secondary-400/30 text-white rounded-tr-sm' 
                      : 'bg-white/10 text-gray-300 rounded-tl-sm'
                  }`}>
                    <p className="text-sm whitespace-pre-wrap">{msg.content}</p>
                  </div>
                  <p className="text-gray-500 text-xs mt-1">{msg.time}</p>
                </div>
              </div>
            ))}
          </div>
          <div className="flex gap-3">
            <input
              type="text"
              value={inputValue}
              onChange={(e) => setInputValue(e.target.value)}
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="输入您的问题..."
              className="flex-1 input-glass px-4 py-2.5"
            />
            <button onClick={handleSend} className="btn-primary px-6 py-2.5 flex items-center gap-2">
              <MessageSquare className="w-4 h-4" />
              发送
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}

