function ToggleSwitch({ active, onToggle, options }: { active: ViewType; onToggle: () => void; options: { teacher: string; student: string } }) {
  return (
    <div className="flex items-center gap-2 p-1 bg-white/5 rounded-xl">
      <button
        onClick={onToggle}
        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300 ${
          active === 'teacher'
            ? 'bg-gradient-to-r from-secondary-400/30 to-primary-600/30 text-secondary-400 shadow-lg shadow-purple-500/20'
            : 'text-gray-400 hover:text-white'
        }`}
      >
        {options.teacher}
      </button>
      <button
        onClick={onToggle}
        className={`px-4 py-2 rounded-lg text-sm font-medium transition-all duration-300 ${
          active === 'student'
            ? 'bg-gradient-to-r from-secondary-400/30 to-primary-600/30 text-secondary-400 shadow-lg shadow-purple-500/20'
            : 'text-gray-400 hover:text-white'
        }`}
      >
        {options.student}
      </button>
    </div>
  );
}

