function ExportModal({ onClose }: { onClose: () => void }) {
  const [selectedFormat, setSelectedFormat] = useState<string>('');

  const formats = [
    { id: 'word', label: 'Word格式', icon: <FileCode className="w-6 h-6 text-blue-400" />, desc: '适合打印和编辑' },
    { id: 'excel', label: 'Excel格式', icon: <FileSpreadsheet className="w-6 h-6 text-green-400" />, desc: '适合数据统计分析' },
    { id: 'pdf', label: 'PDF格式', icon: <FileText className="w-6 h-6 text-red-400" />, desc: '适合存档和分享' },
    { id: 'special', label: '专用题库格式', icon: <Grid3X3 className="w-6 h-6 text-purple-400" />, desc: '支持导入到其他系统' },
  ];

  const handleExport = () => {
    onClose();
    alert(`题库已导出为${formats.find(f => f.id === selectedFormat)?.label || '指定'}格式！`);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div className="absolute inset-0 bg-black/60 backdrop-blur-sm" onClick={onClose} />
      <div className="relative glass-card w-full max-w-lg p-6 rounded-2xl">
        <div className="flex items-center justify-between mb-6">
          <h3 className="text-xl font-bold text-white">导出题库</h3>
          <button onClick={onClose} className="p-2 rounded-lg hover:bg-white/10 text-gray-400 hover:text-white transition-colors">
            <XCircle className="w-5 h-5" />
          </button>
        </div>

        <div className="space-y-3 mb-6">
          {formats.map((format) => (
            <button
              key={format.id}
              onClick={() => setSelectedFormat(format.id)}
              className={`w-full flex items-center gap-4 p-4 rounded-xl transition-all ${
                selectedFormat === format.id
                  ? 'bg-secondary-400/20 border border-secondary-400/50'
                  : 'bg-white/5 hover:bg-white/10'
              }`}
            >
              <div className="w-12 h-12 rounded-lg bg-white/5 flex items-center justify-center">
                {format.icon}
              </div>
              <div className="text-left">
                <p className="text-white font-medium">{format.label}</p>
                <p className="text-gray-500 text-sm">{format.desc}</p>
              </div>
              {selectedFormat === format.id && <CheckCircle2 className="w-5 h-5 text-secondary-400 ml-auto" />}
            </button>
          ))}
        </div>

        <div className="flex gap-3">
          <button onClick={onClose} className="flex-1 py-2.5 rounded-xl bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-colors">
            取消
          </button>
          <button 
            onClick={handleExport}
            disabled={!selectedFormat}
            className="flex-1 py-2.5 rounded-xl bg-gradient-to-r from-secondary-400 to-primary-600 text-white font-medium disabled:opacity-50 disabled:cursor-not-allowed"
          >
            确认导出
          </button>
        </div>
      </div>
    </div>
  );
}

