function StudentExamView() {
  const [currentQuestion, setCurrentQuestion] = useState(1);
  const [answers, setAnswers] = useState<Record<number, string>>({});
  const [timeLeft, setTimeLeft] = useState(5340);
  const [playCounts, setPlayCounts] = useState<Record<number, number>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  useEffect(() => {
    const timer = setInterval(() => {
      setTimeLeft(prev => Math.max(0, prev - 1));
    }, 1000);
    return () => clearInterval(timer);
  }, []);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = seconds % 60;
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0')}`;
  };

  const examQuestions = [
    { id: 1, type: 'single', content: '函数 f(x) = x² 在 x=2 处的导数值为？', options: ['2', '4', '8', '1'] },
    { id: 2, type: 'single', content: '下列哪个是等差数列 2, 5, 8, 11... 的第10项？', options: ['26', '29', '32', '35'] },
    { id: 3, type: 'multiple', content: '下列哪些是 Python 的内置数据类型？', options: ['int', 'list', 'array', 'dict'] },
    { id: 4, type: 'multiple', content: '高等数学中，下列哪些是常见的极限类型？', options: ['0/0型', '∞/∞型', '0·∞型', '1^∞型'] },
    { id: 5, type: 'judge', content: 'Python中，列表是可变对象，元组是不可变对象', options: ['正确', '错误'] },
    { id: 6, type: 'judge', content: '定积分的值与被积函数的原函数选取无关', options: ['正确', '错误'] },
    { id: 7, type: 'fill', content: '∫x dx = ____ + C' },
    { id: 8, type: 'fill', content: 'lim(x→0) sin(x)/x = ____' },
    { id: 9, type: 'listen', content: '听音频回答：这段音频中提到的数学概念是什么？', audio: 'math_concept.mp3', maxPlays: 3 },
    { id: 10, type: 'listen', content: '听音频回答：Python中的哪个关键字用于定义函数？', audio: 'python_func.mp3', maxPlays: 2 },
  ];

  const handleAnswer = (questionId: number, answer: string) => {
    setAnswers(prev => ({ ...prev, [questionId]: answer }));
  };

  const handleAudioPlay = (questionId: number) => {
    const question = examQuestions.find(q => q.id === questionId);
    if (!question || question.type !== 'listen') return;
    
    const currentCount = playCounts[questionId] || 0;
    const maxPlays = question.maxPlays || 0;
    
    if (maxPlays > 0 && currentCount >= maxPlays) {
      return;
    }
    
    setPlayCounts(prev => ({ ...prev, [questionId]: currentCount + 1 }));
  };

  const handleSubmit = () => {
    if (isSubmitting) return;
    setIsSubmitting(true);
    
    const unanswered = examQuestions.filter(q => !answers[q.id]).length;
    if (unanswered > 0) {
      if (!window.confirm(`您还有 ${unanswered} 道题未作答，确定要提交吗？`)) {
        setIsSubmitting(false);
        return;
      }
    }
    
    setTimeout(() => {
      alert('试卷提交成功！');
      setIsSubmitting(false);
    }, 1500);
  };

  const currentPlayCount = playCounts[currentQuestion] || 0;
  const currentQuestionData = examQuestions[currentQuestion - 1];
  const maxPlays = currentQuestionData?.maxPlays || 0;
  const isAudioLocked = maxPlays > 0 && currentPlayCount >= maxPlays;

  return (
    <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
      <div className="lg:col-span-3">
        <div className="glass-card p-6 rounded-2xl">
          <div className="flex items-center justify-between mb-6">
            <div>
              <h3 className="text-white font-bold">高等数学-单元测验</h3>
              <p className="text-gray-400 text-sm">共 {examQuestions.length} 道题，满分 100 分</p>
            </div>
            <div className={`px-4 py-2 rounded-xl font-mono text-lg font-bold ${timeLeft < 300 ? 'bg-red-500/20 text-red-400 animate-pulse' : 'bg-secondary-400/20 text-secondary-400'}`}>
              <Clock className="w-5 h-5 inline mr-2" />
              {formatTime(timeLeft)}
            </div>
          </div>

          <div className="mb-6">
            <div className="flex items-center gap-3 mb-4">
              <span className={`w-10 h-10 rounded-lg flex items-center justify-center text-sm font-bold ${
                currentQuestionData?.type === 'single' ? 'bg-blue-500/20 text-blue-400' :
                currentQuestionData?.type === 'multiple' ? 'bg-green-500/20 text-green-400' :
                currentQuestionData?.type === 'judge' ? 'bg-yellow-500/20 text-yellow-400' :
                currentQuestionData?.type === 'fill' ? 'bg-orange-500/20 text-orange-400' :
                'bg-purple-500/20 text-purple-400'
              }`}>
                {currentQuestionData?.type === 'single' ? '单选' :
                 currentQuestionData?.type === 'multiple' ? '多选' :
                 currentQuestionData?.type === 'judge' ? '判断' :
                 currentQuestionData?.type === 'fill' ? '填空' : '听力'}
              </span>
              <span className="text-gray-400">第 {currentQuestion} 题</span>
            </div>

            <p className="text-white text-lg mb-6">{currentQuestionData?.content}</p>

            {currentQuestionData?.type === 'listen' ? (
              <div className="p-6 bg-white/5 rounded-xl">
                <div className="flex items-center gap-4">
                  <button 
                    onClick={() => handleAudioPlay(currentQuestion)}
                    disabled={isAudioLocked}
                    className={`w-14 h-14 rounded-full flex items-center justify-center transition-all ${
                      isAudioLocked 
                        ? 'bg-gray-600/30 text-gray-500 cursor-not-allowed' 
                        : 'bg-gradient-to-br from-secondary-400 to-purple-600 text-white hover:shadow-lg hover:shadow-purple-500/30'
                    }`}
                  >
                    {isAudioLocked ? <Lock className="w-6 h-6" /> : <Mic className="w-7 h-7" />}
                  </button>
                  <div className="flex-1">
                    <div className="flex items-center gap-2">
                      <p className="text-gray-300">音频播放次数：{currentPlayCount}/{maxPlays}</p>
                      {isAudioLocked && <Lock className="w-4 h-4 text-red-400" />}
                    </div>
                    {isAudioLocked ? (
                      <p className="text-red-400 text-sm mt-1">音频播放次数已达上限，无法继续播放</p>
                    ) : (
                      <div className="mt-2 flex items-center gap-2">
                        <button 
                          onClick={() => handleAudioPlay(currentQuestion)}
                          className="px-4 py-2 rounded-lg bg-gradient-to-r from-secondary-400/20 to-purple-600/20 text-secondary-400 hover:from-secondary-400/30 hover:to-purple-600/30 transition-all text-sm font-medium flex items-center gap-2"
                        >
                          <Play className="w-4 h-4" />
                          播放音频
                        </button>
                      </div>
                    )}
                  </div>
                </div>
                <input 
                  type="text" 
                  placeholder="请输入您的答案..."
                  className="w-full mt-4 input-glass px-4 py-3"
                  value={answers[currentQuestion] || ''}
                  onChange={(e) => handleAnswer(currentQuestion, e.target.value)}
                />
              </div>
            ) : currentQuestionData?.type === 'fill' ? (
              <input 
                type="text" 
                placeholder="请输入您的答案..."
                className="w-full input-glass px-4 py-3 text-lg"
                value={answers[currentQuestion] || ''}
                onChange={(e) => handleAnswer(currentQuestion, e.target.value)}
              />
            ) : (
              <div className="space-y-3">
                {currentQuestionData?.options?.map((option, index) => {
                  const optionLabel = ['A', 'B', 'C', 'D'][index];
                  const isSelected = answers[currentQuestion]?.includes(optionLabel);
                  return (
                    <button
                      key={optionLabel}
                      onClick={() => {
                        if (currentQuestionData?.type === 'multiple') {
                          const current = answers[currentQuestion] || '';
                          const newAnswer = current.includes(optionLabel)
                            ? current.replace(optionLabel, '')
                            : current + optionLabel;
                          handleAnswer(currentQuestion, newAnswer);
                        } else {
                          handleAnswer(currentQuestion, optionLabel);
                        }
                      }}
                      className={`w-full flex items-center gap-4 p-4 rounded-xl text-left transition-all ${
                        isSelected
                          ? 'bg-secondary-400/20 border border-secondary-400/50'
                          : 'bg-white/5 hover:bg-white/10'
                      }`}
                    >
                      <div className={`w-10 h-10 rounded-lg flex items-center justify-center text-sm font-bold ${
                        isSelected ? 'bg-secondary-400 text-white' : 'bg-white/10 text-gray-400'
                      }`}>
                        {optionLabel}
                      </div>
                      <span className={isSelected ? 'text-white' : 'text-gray-300'}>{option}</span>
                    </button>
                  );
                })}
              </div>
            )}
          </div>

          <div className="flex items-center justify-between">
            <button 
              onClick={() => setCurrentQuestion(Math.max(1, currentQuestion - 1))}
              disabled={currentQuestion === 1}
              className="px-5 py-2.5 rounded-xl bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-all disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:bg-white/5 flex items-center gap-2"
            >
              <ChevronDown className="w-4 h-4 rotate-90" />
              上一题
            </button>
            {currentQuestion === examQuestions.length ? (
              <button 
                onClick={handleSubmit}
                disabled={isSubmitting}
                className="px-6 py-2.5 rounded-xl bg-gradient-to-r from-green-500 to-emerald-600 text-white font-medium hover:shadow-lg hover:shadow-green-500/30 transition-all disabled:opacity-70 disabled:cursor-not-allowed flex items-center gap-2"
              >
                {isSubmitting ? (
                  <>
                    <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                    提交中...
                  </>
                ) : (
                  <>
                    <CheckCircle2 className="w-5 h-5" />
                    提交试卷
                  </>
                )}
              </button>
            ) : (
              <button 
                onClick={() => setCurrentQuestion(Math.min(examQuestions.length, currentQuestion + 1))}
                className="px-5 py-2.5 rounded-xl bg-gradient-to-r from-secondary-400 to-primary-600 text-white font-medium hover:shadow-lg hover:shadow-purple-500/30 transition-all flex items-center gap-2"
              >
                下一题
                <ChevronDown className="w-4 h-4 -rotate-90" />
              </button>
            )}
          </div>
        </div>
      </div>

      <div className="lg:col-span-1">
        <div className="glass-card p-6 rounded-2xl sticky top-20">
          <h4 className="text-white font-medium mb-4 flex items-center gap-2">
            <ListChecks className="w-5 h-5 text-secondary-400" />
            答题卡
          </h4>
          <div className="grid grid-cols-5 gap-2">
            {examQuestions.map((q, index) => {
              const questionNumber = index + 1;
              const isCurrent = currentQuestion === questionNumber;
              const hasAnswer = !!answers[q.id];
              return (
                <button
                  key={q.id}
                  onClick={() => setCurrentQuestion(questionNumber)}
                  className={`w-10 h-10 rounded-lg text-sm font-medium transition-all flex items-center justify-center ${
                    isCurrent
                      ? 'bg-gradient-to-br from-secondary-400 to-purple-600 text-white shadow-lg shadow-purple-500/30'
                      : hasAnswer
                      ? 'bg-green-500/20 text-green-400 border border-green-500/30'
                      : 'bg-white/10 text-gray-400 hover:bg-white/20 border border-white/5'
                  }`}
                >
                  {questionNumber}
                </button>
              );
            })}
          </div>
          <div className="mt-6 pt-6 border-t border-white/10">
            <div className="flex flex-wrap items-center gap-4 text-sm">
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 rounded bg-green-500/20 border border-green-500/30" />
                <span className="text-gray-400">已答</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 rounded bg-white/10 border border-white/5" />
                <span className="text-gray-400">未答</span>
              </div>
              <div className="flex items-center gap-2">
                <div className="w-4 h-4 rounded bg-gradient-to-br from-secondary-400 to-purple-600" />
                <span className="text-gray-400">当前</span>
              </div>
            </div>
            <div className="mt-4 pt-4 border-t border-white/10">
              <div className="flex justify-between text-sm">
                <span className="text-gray-400">答题进度</span>
                <span className="text-secondary-400 font-medium">
                  {Object.keys(answers).length}/{examQuestions.length}
                </span>
              </div>
              <div className="mt-2 h-2 bg-white/10 rounded-full overflow-hidden">
                <div 
                  className="h-full bg-gradient-to-r from-secondary-400 to-purple-600 transition-all duration-300"
                  style={{ width: `${(Object.keys(answers).length / examQuestions.length) * 100}%` }}
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

