function TaskPointCard({ task, onEdit, onDelete }: { task: TrainingTaskPoint; onEdit: () => void; onDelete: () => void }) {
  const getIcon = () => {
    const iconMap: Record<string, React.ReactNode> = {
      Wrench: <Wrench className="w-6 h-6" />,
      Bot: <Terminal className="w-6 h-6" />,
      Printer: <Send className="w-6 h-6" />,
      FileCode: <FileCode className="w-6 h-6" />,
      Database: <Database className="w-6 h-6" />,
      BookOpen: <BookOpen className="w-6 h-6" />,
      Brain: <Brain className="w-6 h-6" />,
    };
    return iconMap[task.icon] || <Wrench className="w-6 h-6" />;
  };

  return (
    <div className="p-4 bg-white/5 rounded-xl hover:bg-white/10 transition-colors">
      <div className="flex items-start gap-4">
        <div className="w-12 h-12 rounded-xl bg-gradient-to-br from-secondary-400/30 to-primary-900/50 flex items-center justify-center text-secondary-400">
          {getIcon()}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <h3 className="text-white font-semibold">{task.name}</h3>
            <span className="px-2 py-0.5 bg-white/10 text-gray-400 rounded text-xs font-mono">
              {task.identifier}
            </span>
          </div>
          <p className="text-gray-400 text-sm mb-2">{task.description}</p>
          <div className="flex flex-wrap gap-2">
            {task.applicableCourses.map((course) => (
              <span key={course} className="px-2 py-1 bg-secondary-400/20 text-secondary-400 rounded-full text-xs">
                <BookOpen className="w-3 h-3 inline mr-1" />
                {course}
              </span>
            ))}
          </div>
        </div>
        <div className="flex flex-col gap-2">
          <button onClick={onEdit} className="p-2 text-gray-400 hover:text-white hover:bg-white/10 rounded-lg transition-colors">
            <Edit2 className="w-4 h-4" />
          </button>
          <button onClick={onDelete} className="p-2 text-gray-400 hover:text-red-400 hover:bg-red-500/10 rounded-lg transition-colors">
            <Trash2 className="w-4 h-4" />
          </button>
        </div>
      </div>
    </div>
  );
}

function TaskPointModal({ isOpen, onClose, onSave, editingTask }: { isOpen: boolean; onClose: () => void; onSave: (task: Omit<TrainingTaskPoint, 'id'>) => void; editingTask?: TrainingTaskPoint }) {
  const [formData, setFormData] = useState<TrainingTaskPoint>({
    id: editingTask?.id || '',
    identifier: editingTask?.identifier || '',
    name: editingTask?.name || '',
    icon: editingTask?.icon || 'Wrench',
    applicableCourses: editingTask?.applicableCourses || [],
    applicableMajors: editingTask?.applicableMajors || [],
    description: editingTask?.description || '',
  });

  useEffect(() => {
    if (editingTask) {
      setFormData(editingTask);
    } else {
      setFormData({
        id: '',
        identifier: '',
        name: '',
        icon: 'Wrench',
        applicableCourses: [],
        applicableMajors: [],
        description: '',
      });
    }
  }, [editingTask, isOpen]);

  const handleCourseToggle = (course: string) => {
    setFormData((prev) => ({
      ...prev,
      applicableCourses: prev.applicableCourses.includes(course)
        ? prev.applicableCourses.filter((c) => c !== course)
        : [...prev.applicableCourses, course],
    }));
  };

  const handleMajorToggle = (major: string) => {
    setFormData((prev) => ({
      ...prev,
      applicableMajors: prev.applicableMajors.includes(major)
        ? prev.applicableMajors.filter((m) => m !== major)
        : [...prev.applicableMajors, major],
    }));
  };

  const handleSubmit = () => {
    if (!formData.identifier || !formData.name) return;
    onSave({ ...formData });
    onClose();
  };

  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
      <div className="glass-card w-full max-w-2xl max-h-[90vh] overflow-y-auto">
        <div className="p-6 border-b border-white/10 flex items-center justify-between">
          <h2 className="text-xl font-bold text-white">{editingTask ? '编辑实训任务点' : '创建实训任务点'}</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>
        <div className="p-6 space-y-6">
          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">任务点唯一标识</label>
            <input
              type="text"
              value={formData.identifier}
              onChange={(e) => setFormData({ ...formData, identifier: e.target.value.toUpperCase() })}
              placeholder="如：DATA_ANALYSIS_PROJECT"
              className="input-glass w-full"
            />
            <p className="text-gray-500 text-xs mt-1">建议使用大写字母和下划线，全局唯一</p>
          </div>

          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">任务点名称</label>
            <input
              type="text"
              value={formData.name}
              onChange={(e) => setFormData({ ...formData, name: e.target.value })}
              placeholder="输入任务点名称"
              className="input-glass w-full"
            />
          </div>

          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">自定义图标</label>
            <div className="flex gap-2 flex-wrap">
              {iconOptions.map((icon) => (
                <button
                  key={icon.value}
                  onClick={() => setFormData({ ...formData, icon: icon.value })}
                  className={`p-3 rounded-lg transition-all duration-300 ${
                    formData.icon === icon.value
                      ? 'bg-secondary-400/30 text-secondary-400 ring-2 ring-secondary-400'
                      : 'bg-white/5 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  {icon.icon}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">适用课程</label>
            <div className="flex gap-2 flex-wrap">
              {mockCourses.map((course) => (
                <button
                  key={course}
                  onClick={() => handleCourseToggle(course)}
                  className={`px-3 py-1.5 rounded-full text-sm transition-all duration-300 ${
                    formData.applicableCourses.includes(course)
                      ? 'bg-secondary-400/30 text-secondary-400'
                      : 'bg-white/5 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  <BookOpen className="w-3 h-3 inline mr-1" />
                  {course}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">适用专业</label>
            <div className="flex gap-2 flex-wrap">
              {mockMajors.map((major) => (
                <button
                  key={major}
                  onClick={() => handleMajorToggle(major)}
                  className={`px-3 py-1.5 rounded-full text-sm transition-all duration-300 ${
                    formData.applicableMajors.includes(major)
                      ? 'bg-primary-500/30 text-primary-400'
                      : 'bg-white/5 text-gray-400 hover:bg-white/10'
                  }`}
                >
                  <GraduationCap className="w-3 h-3 inline mr-1" />
                  {major}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-gray-300 text-sm font-medium mb-2">任务点描述</label>
            <textarea
              value={formData.description}
              onChange={(e) => setFormData({ ...formData, description: e.target.value })}
              placeholder="描述任务点的具体内容和要求"
              rows={3}
              className="input-glass w-full resize-none"
            />
          </div>
        </div>
        <div className="p-6 border-t border-white/10 flex justify-end gap-3">
          <button onClick={onClose} className="px-4 py-2 rounded-lg bg-white/5 text-gray-400 hover:bg-white/10 transition-colors">
            取消
          </button>
          <button onClick={handleSubmit} className="btn-primary">
            {editingTask ? '保存修改' : '创建任务点'}
          </button>
        </div>
      </div>
    </div>
  );
}

function ConfigTab({ taskPoints, onCreate, onEdit, onDelete, onSave }: { 
  taskPoints: TrainingTaskPoint[]; 
  onCreate: () => void; 
  onEdit: (task: TrainingTaskPoint) => void; 
  onDelete: (taskId: string) => void;
  onSave: (task: Omit<TrainingTaskPoint, 'id'>) => void;
}) {
  const [searchQuery, setSearchQuery] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingTask, setEditingTask] = useState<TrainingTaskPoint | undefined>();

  const filteredTaskPoints = taskPoints.filter((t) =>
    t.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
    t.identifier.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const handleCreate = () => {
    setEditingTask(undefined);
    setIsModalOpen(true);
  };

  const handleEdit = (task: TrainingTaskPoint) => {
    setEditingTask(task);
    setIsModalOpen(true);
  };

  return (
    <div className="space-y-6">
      <div className="p-6 bg-gradient-to-r from-secondary-400/10 to-primary-900/20 rounded-xl border border-secondary-400/20">
        <h3 className="text-white font-semibold mb-2">验收要求1：任务点自定义配置</h3>
        <p className="text-gray-400 text-sm">支持填写任务唯一标识、自定义图标样式、限定可用课程/专业范围</p>
        <div className="mt-4 flex flex-wrap gap-2">
          <span className="px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs flex items-center gap-1">
            <Check className="w-3 h-3" /> 唯一标识配置
          </span>
          <span className="px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs flex items-center gap-1">
            <Check className="w-3 h-3" /> 自定义图标
          </span>
          <span className="px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs flex items-center gap-1">
            <Check className="w-3 h-3" /> 课程范围限定
          </span>
          <span className="px-3 py-1 bg-green-500/20 text-green-400 rounded-full text-xs flex items-center gap-1">
            <Check className="w-3 h-3" /> 专业范围限定
          </span>
        </div>
      </div>

      <div className="glass-card p-6">
        <div className="flex items-center justify-between mb-6">
          <div>
            <h2 className="text-lg font-semibold text-white flex items-center gap-2">
              <Settings className="w-5 h-5 text-secondary-400" />
              任务点配置列表
            </h2>
            <p className="text-gray-400 text-sm mt-1">已配置的外部实训任务点，支持搜索和管理</p>
          </div>
          <button onClick={handleCreate} className="btn-primary flex items-center gap-2">
            <Plus className="w-4 h-4" />
            创建任务点
          </button>
        </div>

        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
          <input
            type="text"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder="搜索任务点名称或标识..."
            className="input-glass pl-10 pr-4 py-2 w-full"
          />
        </div>

        <div className="space-y-4">
          {filteredTaskPoints.map((task) => (
            <TaskPointCard
              key={task.id}
              task={task}
              onEdit={() => handleEdit(task)}
              onDelete={() => onDelete(task.id)}
            />
          ))}
        </div>

        {filteredTaskPoints.length === 0 && (
          <div className="text-center py-12 text-gray-500">
            <Folder className="w-12 h-12 mx-auto mb-4 opacity-50" />
            <p>暂无任务点配置</p>
            <button onClick={handleCreate} className="mt-4 text-secondary-400 hover:text-white transition-colors">
              立即创建
            </button>
          </div>
        )}
      </div>

      <TaskPointModal
        isOpen={isModalOpen}
        onClose={() => setIsModalOpen(false)}
        onSave={onSave}
        editingTask={editingTask}
      />
    </div>
  );
}

