export default function Training() {
  const [taskPoints, setTaskPoints] = useState<TrainingTaskPoint[]>(mockTaskPoints);
  const [activeTab, setActiveTab] = useState<TabType>('config');
  const [editingTask, setEditingTask] = useState<TrainingTaskPoint | undefined>();

  const handleCreateTask = () => {
    setEditingTask(undefined);
  };

  const handleEditTask = (task: TrainingTaskPoint) => {
    setEditingTask(task);
  };

  const handleDeleteTask = (taskId: string) => {
    setTaskPoints((prev) => prev.filter((t) => t.id !== taskId));
  };

  const handleSaveTask = (task: Omit<TrainingTaskPoint, 'id'>) => {
    if (editingTask) {
      setTaskPoints((prev) => prev.map((t) => (t.id === editingTask.id ? { ...t, ...task } : t)));
    } else {
      setTaskPoints((prev) => [...prev, { ...task, id: Date.now().toString() }]);
    }
  };

  return (
    <div className="animate-fade-in">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-white mb-2">外部实训开放接口管理</h1>
        <p className="text-gray-400">超级管理员工作台 - 配置实训任务点、管理开放接口</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-1">
          <div className="glass-card p-4 sticky top-20">
            <h2 className="text-white font-semibold mb-4">验收标准导航</h2>
            <div className="space-y-2">
              {tabs.map((tab) => {
                const Icon = tab.icon;
                return (
                  <button
                    key={tab.id}
                    onClick={() => setActiveTab(tab.id)}
                    className={`w-full flex items-center gap-3 p-3 rounded-xl text-left transition-all ${
                      activeTab === tab.id
                        ? 'bg-secondary-400/30 text-secondary-400 border border-secondary-400/50'
                        : 'text-gray-400 hover:text-white hover:bg-white/10'
                    }`}
                  >
                    <Icon className="w-5 h-5" />
                    <div>
                      <p className="text-sm font-medium">{tab.label}</p>
                      <p className="text-xs text-gray-500">{tab.desc}</p>
                    </div>
                  </button>
                );
              })}
            </div>
          </div>
        </div>

        <div className="lg:col-span-3">
          {activeTab === 'config' && (
            <ConfigTab 
              taskPoints={taskPoints} 
              onCreate={handleCreateTask}
              onEdit={handleEditTask}
              onDelete={handleDeleteTask}
              onSave={handleSaveTask}
            />
          )}
          {activeTab === 'preview' && <PreviewTab />}
          {activeTab === 'query' && <QueryTab />}
          {activeTab === 'push' && <PushTab />}
          {activeTab === 'docs' && <DocsTab />}
        </div>
      </div>
    </div>
  );
}

