import { useState, useEffect } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useStore } from '../store/useStore';
import { 
  LayoutDashboard, 
  BookOpen, 
  PenTool, 
  ExternalLink, 
  ChevronLeft, 
  ChevronRight,
  Bell,
  LogOut,
  User,
  Menu,
  Smartphone,
  Monitor,
  Home,
  Brain,
  BarChart3,
  Users,
  GraduationCap,
  Wrench,
  Settings,
  Sparkles,
  Database,
} from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
}

const adminNavItems = [
  { id: '/', label: '一体化平台', icon: Home },
  { id: '/dashboard', label: '管理控制台', icon: LayoutDashboard },
  { id: '/exam', label: '智慧考试系统', icon: PenTool },
  { id: '/teaching', label: '智慧教学系统', icon: BookOpen },
  { id: '/training', label: '外部实训开放接口', icon: ExternalLink },
  { id: '/expand#project', label: '实训项目管理', icon: Wrench },
  { id: '/expand#dashboard', label: '数据看板管理', icon: BarChart3 },
  { id: '/expand#teacher', label: '师资管理', icon: GraduationCap },
  { id: '/expand#permissions', label: '权限管理', icon: Users },
  { id: '/expand#settings', label: '系统设置', icon: Settings },
  { id: '/expand#workshop', label: '教研协调工坊', icon: Database },
  { id: '/expand', label: '智问AI实践', icon: Brain },
];

const teacherNavItems = [
  { id: '/', label: '一体化平台', icon: Home },
  { id: '/dashboard', label: '工作台', icon: LayoutDashboard },
  { id: '/exam', label: '智慧考试系统', icon: PenTool },
  { id: '/teaching', label: '智慧教学系统', icon: BookOpen },
  { id: '/expand', label: '智问AI实践', icon: Brain },
  { id: '/expand#workshop', label: '教研协调工坊', icon: Database },
  { id: '/expand#project', label: '实训项目管理', icon: Wrench },
  { id: '/expand#dashboard', label: '数据看板管理', icon: BarChart3 },
];

const studentNavItems = [
  { id: '/', label: '一体化平台', icon: Home },
  { id: '/dashboard', label: '学习中心', icon: LayoutDashboard },
  { id: '/exam', label: '智慧考试系统', icon: PenTool },
  { id: '/teaching', label: '智慧教学系统', icon: BookOpen },
];

export default function Layout({ children }: LayoutProps) {
  const { user, sideMenuCollapsed, toggleSideMenu, logout, notifications } = useStore();
  const [showMobileMenu, setShowMobileMenu] = useState(false);
  const [isMobileView, setIsMobileView] = useState(false);
  const navigate = useNavigate();
  const location = useLocation();

  useEffect(() => {
    const checkMobileView = () => {
      setIsMobileView(window.innerWidth < 768);
      if (window.innerWidth >= 768) {
        setShowMobileMenu(false);
      }
    };
    checkMobileView();
    window.addEventListener('resize', checkMobileView);
    return () => window.removeEventListener('resize', checkMobileView);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  const handleNavClick = (path: string) => {
    navigate(path);
    setShowMobileMenu(false);
  };

  const getNavItems = () => {
    switch (user?.role) {
      case 'admin':
        return adminNavItems;
      case 'teacher':
        return teacherNavItems;
      case 'student':
        return studentNavItems;
      default:
        return teacherNavItems;
    }
  };

  return (
    <div className="min-h-screen flex">
      <aside
        className={`fixed left-0 top-0 h-screen bg-primary-900/60 backdrop-blur-xl border-r border-white/10 transition-all duration-300 z-50 ${
          sideMenuCollapsed ? 'w-20' : 'w-64'
        } ${showMobileMenu ? 'translate-x-0' : '-translate-x-full'} md:translate-x-0`}
      >
        <div className="flex items-center h-16 px-4 border-b border-white/10">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-gradient-to-br from-secondary-400 to-primary-900 rounded-card flex items-center justify-center hover:shadow-btn transition-all duration-300">
              <Sparkles className="w-6 h-6 text-white" />
            </div>
            {!sideMenuCollapsed && (
              <span className="text-white font-bold text-lg animate-fade-in">一体化平台</span>
            )}
          </div>
        </div>

        <nav className="p-4 space-y-2">
          {getNavItems().map((item) => {
            const Icon = item.icon;
            const isActive = item.id.startsWith('/expand')
              ? location.pathname === '/expand' && (item.id === '/expand' ? location.hash === '' : location.hash === `#${item.id.split('#')[1]}`)
              : location.pathname === item.id;
            return (
              <button
                key={item.id}
                onClick={() => handleNavClick(item.id)}
                className={`w-full flex items-center gap-3 px-4 py-3 rounded-card transition-all duration-300 ${
                  isActive
                    ? 'bg-gradient-to-r from-secondary-400/30 to-primary-900/50 text-secondary-400 shadow-soft-hover'
                    : 'text-gray-400 hover:text-white hover:bg-white/10 hover:shadow-soft'
                }`}
              >
                <Icon className="w-5 h-5 flex-shrink-0" />
                {!sideMenuCollapsed && (
                  <span className="font-medium animate-fade-in">{item.label}</span>
                )}
              </button>
            );
          })}
        </nav>

        <div className="absolute bottom-4 left-4 right-4 space-y-2">
          <button
            onClick={handleLogout}
            className="w-full flex items-center justify-center gap-2 py-2.5 rounded-card bg-red-500/20 text-red-400 hover:bg-red-500/30 hover:text-red-300 transition-all duration-300"
          >
            <LogOut className="w-5 h-5" />
            {!sideMenuCollapsed && <span className="text-sm font-medium">退出</span>}
          </button>
          <button
            onClick={toggleSideMenu}
            className="w-full flex items-center justify-center py-2.5 rounded-card bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-all duration-300"
          >
            {sideMenuCollapsed ? <ChevronRight className="w-5 h-5" /> : <ChevronLeft className="w-5 h-5" />}
          </button>
        </div>
      </aside>

      <div className={`flex-1 transition-all duration-300 ${sideMenuCollapsed ? 'ml-20' : 'ml-64'}`}>
        <header className={`fixed top-0 right-0 h-16 bg-primary-900/40 backdrop-blur-xl border-b border-white/10 z-40 transition-all duration-300 ${sideMenuCollapsed ? 'left-20' : 'left-64'}`}>
          <div className="h-full px-4 flex items-center justify-between">
            <button
              onClick={() => setShowMobileMenu(!showMobileMenu)}
              className="md:hidden p-2 rounded-lg text-gray-400 hover:text-white hover:bg-white/10 transition-all duration-300"
            >
              <Menu className="w-6 h-6" />
            </button>

            <div className="flex items-center gap-3">
              {user && (
                <>
                  <button className="relative p-2 rounded-lg text-gray-400 hover:text-white hover:bg-white/10 transition-all duration-300">
                    <Bell className="w-5 h-5" />
                    {notifications.length > 0 && (
                      <span className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-xs rounded-full flex items-center justify-center animate-pulse">
                        {notifications.length}
                      </span>
                    )}
                  </button>

                  <button 
                    className="hidden md:flex items-center gap-2 px-3 py-1.5 rounded-card bg-white/5 text-gray-400 hover:text-white hover:bg-white/10 transition-all duration-300"
                    title="视图切换"
                  >
                    {isMobileView ? (
                      <><Monitor className="w-4 h-4" /><span className="text-sm">PC视图</span></>
                    ) : (
                      <><Smartphone className="w-4 h-4" /><span className="text-sm">移动端</span></>
                    )}
                  </button>

                  <div className="flex items-center gap-3 pl-4 border-l border-white/10">
                    <div className="w-9 h-9 bg-gradient-to-br from-secondary-400 to-primary-900 rounded-full flex items-center justify-center hover:shadow-btn transition-all duration-300">
                      <User className="w-5 h-5 text-white" />
                    </div>
                    <div className="hidden sm:block">
                      <p className="text-white text-sm font-medium">{user.realName}</p>
                      <p className="text-gray-500 text-xs">
                        {user.role === 'admin' ? '超级管理员' : user.role === 'teacher' ? '教师' : '学生'}
                      </p>
                    </div>
                  </div>
                </>
              )}
            </div>
          </div>
        </header>

        <main className="pt-16 px-3 sm:px-4 md:px-6 lg:px-8 pb-8 min-h-[calc(100vh-4rem)]">
          {children}
        </main>
      </div>

      {showMobileMenu && (
        <div
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-40 md:hidden animate-fade-in"
          onClick={() => setShowMobileMenu(false)}
        />
      )}
    </div>
  );
}