interface StatCardProps {
  title: string;
  value: number;
  icon: React.ReactNode;
  color: string;
  trend?: string;
}

function StatCard({ title, value, icon, color, trend }: StatCardProps) {
  const [displayValue, setDisplayValue] = useState(0);

  useEffect(() => {
    const duration = 1500;
    const steps = 60;
    const increment = value / steps;
    let current = 0;
    
    const timer = setInterval(() => {
      current += increment;
      if (current >= value) {
        setDisplayValue(value);
        clearInterval(timer);
      } else {
        setDisplayValue(Math.floor(current));
      }
    }, duration / steps);

    return () => clearInterval(timer);
  }, [value]);

  return (
    <div className="glass-card p-6 animate-fade-in hover:shadow-xl hover:shadow-purple-500/10 transition-all duration-300">
      <div className="flex items-center justify-between mb-4">
        <div className={`w-12 h-12 rounded-xl bg-gradient-to-br ${color} flex items-center justify-center`}>
          {icon}
        </div>
        {trend && (
          <div className="flex items-center gap-1 text-green-400 text-sm">
            <TrendingUp className="w-4 h-4" />
            <span>{trend}</span>
          </div>
        )}
      </div>
      <p className="text-gray-400 text-sm mb-1">{title}</p>
      <p className="text-3xl font-bold text-white">{displayValue}</p>
    </div>
  );
}

interface NotificationCardProps {
  notification: {
    id: string;
    title: string;
    content: string;
    time: string;
    type: 'info' | 'warning' | 'success';
  };
}

function NotificationCard({ notification }: NotificationCardProps) {
  const icons = {
    info: <Info className="w-5 h-5 text-blue-400" />,
    warning: <AlertTriangle className="w-5 h-5 text-yellow-400" />,
    success: <CheckCircle className="w-5 h-5 text-green-400" />,
  };

  return (
    <div className="glass-card p-4 hover:bg-white/10 transition-all duration-300 cursor-pointer group">
      <div className="flex gap-4">
        <div className="w-10 h-10 rounded-lg bg-white/5 flex items-center justify-center flex-shrink-0 group-hover:bg-white/10 transition-colors">
          {icons[notification.type]}
        </div>
        <div className="flex-1 min-w-0">
          <div className="flex items-start justify-between gap-2">
            <h4 className="text-white font-medium text-sm truncate">{notification.title}</h4>
            <span className="text-gray-500 text-xs flex-shrink-0">{notification.time}</span>
          </div>
          <p className="text-gray-400 text-sm mt-1 line-clamp-2">{notification.content}</p>
        </div>
      </div>
    </div>
  );
}

