import { create } from 'zustand'

export type Role = 'admin' | 'teacher' | 'student'

export interface User {
  id: string
  username: string
  realName: string
  role: Role
  avatar?: string
}

export interface DashboardStats {
  totalCourses: number
  completedCourses: number
  ongoingExams: number
  upcomingTrainings: number
}

export interface Notification {
  id: string
  title: string
  content: string
  time: string
  type: 'info' | 'warning' | 'success'
}

export interface CourseCard {
  id: string
  title: string
  teacher: string
  cover: string
  progress: number
  category: string
}

export interface Course {
  id: string
  title: string
  description: string
  teacherId: string
  teacherName: string
  category: string
  status: 'draft' | 'published' | 'archived'
  createTime: string
  studentCount: number
}

export interface TeachingPlan {
  id: string
  courseId: string
  courseTitle: string
  semester: string
  schedule: string
  progress: number
}

export interface Courseware {
  id: string
  title: string
  type: 'ppt' | 'pdf' | 'video' | 'document'
  size: string
  uploadTime: string
  courseId: string
}

export interface Exam {
  id: string
  title: string
  courseId: string
  courseTitle: string
  type: 'quiz' | 'midterm' | 'final'
  duration: number
  totalScore: number
  status: 'upcoming' | 'ongoing' | 'finished'
  startTime: string
  endTime: string
}

export interface Question {
  id: string
  type: 'single' | 'multiple' | 'judge' | 'fill'
  content: string
  options?: string[]
  answer: string | string[]
  score: number
}

export interface ExamResult {
  id: string
  examId: string
  examTitle: string
  userId: string
  userName: string
  score: number
  totalScore: number
  submitTime: string
  status: 'completed' | 'partial'
}

export interface TrainingProject {
  id: string
  title: string
  description: string
  category: string
  duration: string
  capacity: number
  enrolledCount: number
  status: 'open' | 'closed' | 'in_progress'
  startTime: string
  equipment: string[]
}

export interface Equipment {
  id: string
  name: string
  model: string
  status: 'available' | 'in_use' | 'maintenance'
  location: string
  lastMaintenance: string
}

export interface Reservation {
  id: string
  projectId: string
  projectTitle: string
  userId: string
  userName: string
  date: string
  timeSlot: string
  status: 'pending' | 'approved' | 'rejected'
}

interface Store {
  user: User | null
  isLoggedIn: boolean
  sideMenuCollapsed: boolean
  stats: DashboardStats
  notifications: Notification[]
  courses: Course[]
  courseCards: CourseCard[]
  teachingPlans: TeachingPlan[]
  coursewares: Courseware[]
  exams: Exam[]
  examResults: ExamResult[]
  trainingProjects: TrainingProject[]
  equipments: Equipment[]
  reservations: Reservation[]
  
  login: (username: string, password: string, role: Role) => boolean
  logout: () => void
  toggleSideMenu: () => void
  getRolePermissions: () => string[]
}

