const loadFromStorage = () => {
  const savedUser = localStorage.getItem('trae_user')
  const savedRole = localStorage.getItem('trae_role') as Role | null
  if (savedUser && savedRole && mockUsers[savedRole]) {
    return {
      user: mockUsers[savedRole],
      isLoggedIn: true,
      stats: mockStats[savedRole],
      notifications: mockNotifications[savedRole],
    }
  }
  return {
    user: null,
    isLoggedIn: false,
    stats: mockStats.admin,
    notifications: mockNotifications.admin,
  }
}

const persistedState = loadFromStorage()

export const useStore = create<Store>((set, get) => ({
  user: persistedState.user,
  isLoggedIn: persistedState.isLoggedIn,
  sideMenuCollapsed: false,
  stats: persistedState.stats,
  notifications: persistedState.notifications,
  courses: mockCourses,
  courseCards: mockCourseCards,
  teachingPlans: mockTeachingPlans,
  coursewares: mockCoursewares,
  exams: mockExams,
  examResults: mockExamResults,
  trainingProjects: mockTrainingProjects,
  equipments: mockEquipments,
  reservations: mockReservations,

  login: (username: string, password: string, role: Role) => {
    if (password === '123456' && mockUsers[role].username === username) {
      set({ 
        user: mockUsers[role], 
        isLoggedIn: true,
        stats: mockStats[role],
        notifications: mockNotifications[role]
      })
      localStorage.setItem('trae_user', JSON.stringify(mockUsers[role]))
      localStorage.setItem('trae_role', role)
      return true
    }
    return false
  },

  logout: () => {
    set({ user: null, isLoggedIn: false })
    localStorage.removeItem('trae_user')
    localStorage.removeItem('trae_role')
    localStorage.removeItem('trae_lastPath')
  },

  toggleSideMenu: () => {
    set((state) => ({ sideMenuCollapsed: !state.sideMenuCollapsed }))
  },

  getRolePermissions: () => {
    const { user } = get()
    if (!user) return []
    
    const permissions: Record<Role, string[]> = {
      admin: ['系统管理', '用户管理', '资源审核', '配置管理', '课程管理', '考试管理', '实训管理'],
      teacher: ['课程管理', '教学计划', '作业管理', '成绩管理', '考试管理'],
      student: ['课程学习', '在线考试', '实训预约', '成绩查询'],
    }
    return permissions[user.role]
  },
}))